content = open('backend/src/modules/professionals/professional-schedule.routes.ts', 'r', encoding='utf-8').read()
old = '        INSERT INTO professional_schedules (tenant_id, professional_id, day_of_week, is_working, start_time, end_time, slot_minutes)\n        VALUES (${tenantId}, ${req.params.id}, ${day.dayOfWeek}, ${day.isWorking}, ${day.startTime}, ${day.endTime}, ${day.slotMinutes ?? 30})\n        ON CONFLICT (professional_id, day_of_week) DO UPDATE SET\n          is_working = EXCLUDED.is_working,\n          start_time = EXCLUDED.start_time,\n          end_time = EXCLUDED.end_time,\n          slot_minutes = EXCLUDED.slot_minutes,\n          updated_at = now()'
new = '        INSERT INTO professional_schedules (tenant_id, professional_id, day_of_week, is_working, start_time, end_time, slot_minutes, break_start, break_end)\n        VALUES (${tenantId}, ${req.params.id}, ${day.dayOfWeek}, ${day.isWorking}, ${day.startTime}, ${day.endTime}, ${day.slotMinutes ?? 30}, ${day.breakStart ?? null}, ${day.breakEnd ?? null})\n        ON CONFLICT (professional_id, day_of_week) DO UPDATE SET\n          is_working = EXCLUDED.is_working,\n          start_time = EXCLUDED.start_time,\n          end_time = EXCLUDED.end_time,\n          slot_minutes = EXCLUDED.slot_minutes,\n          break_start = EXCLUDED.break_start,\n          break_end = EXCLUDED.break_end,\n          updated_at = now()'
content = content.replace(old, new, 1)
open('backend/src/modules/professionals/professional-schedule.routes.ts', 'w', encoding='utf-8').write(content)
print('OK - break:', content.count('break_start'))
